def _seed_default_loops(apps, schema_editor):
    """Idempotently seed the default loops + prompts, every loop PAUSED.

    ``get_or_create`` by ``name`` so a re-run (or a fake-applied initial whose
    rows already exist) creates nothing new and never clobbers an
    operator-edited row. A prompt-backed loop's :class:`Prompt` is seeded first
    so the nullable FK resolves under the loop XOR constraint.
    """
    Loop = apps.get_model("core", "Loop")
    Prompt = apps.get_model("core", "Prompt")
    for name, delay_seconds, daily_at, prompt_body in _DEFAULT_LOOPS:
        prompt = None
        if prompt_body is not None:
            prompt, _ = Prompt.objects.get_or_create(
                name=name,
                defaults={"body": prompt_body, "description": f"Default loop prompt for {name!r}."},
            )
        defaults = {"delay_seconds": delay_seconds, "daily_at": daily_at, "enabled": False}
        if prompt is not None:
            defaults["prompt"] = prompt
        else:
            defaults["script"] = f"src/teatree/loops/{name}/loop.py"
        Loop.objects.get_or_create(name=name, defaults=defaults)


